import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"束缚行动的绷带","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/束缚行动的绷带.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/束缚行动的绷带.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/束缚行动的绷带.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"束缚行动的绷带",tabindex:"-1"},[s("束缚行动的绷带 "),e("a",{class:"header-anchor",href:"#束缚行动的绷带","aria-label":'Permalink to "束缚行动的绷带"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="束缚行动的绷带-1" tabindex="-1">束缚行动的绷带 <a class="header-anchor" href="#束缚行动的绷带-1" aria-label="Permalink to &quot;束缚行动的绷带&quot;">​</a></h1><p>束缚行动的绷带<br> D+1000<br> “陛下所要通过我的手散播的——是人类的幸福吗？是和我纯洁的爱所要施与人类的幸福一般的吗？<br> ——不是！对于这个幸福陛下会发抖的。<br> 朝廷的政策已经创造了一种新的幸福——这是一种朝廷富有而足够施舍的幸福，它在人心中唤起新的欲望，这种欲望只有这种幸福可以使之满足。<br> 朝廷在自己的货币上印着真理。一切不同于此的货币都是禁止通行的。<br> 但是，能满足朝廷的，同时也能满足我吗？我的兄弟之爱是用来限制兄弟的权利的吗？<br> 在准许他思想之前，我能知道他是幸福的吗？陛下，请你不要选用我作为您替我们印铸好了的幸福的人。<br> 我不得不拒绝发行这种货币。——我不能做君主的仆人。”</p><p>这是一把体积3的长剑，其的武器伤害为6L，具有【法破】，</p><p>其完全由鲜红的绷带组成，在挥舞这把剑时，你的动作会被其上的绷带引导至完善，但是绷带也会束缚你，让你不得随心所欲的动作，在使用这把剑时，你的攻击检定改为25+2的预设检定。</p><p>每场影片结束时，若你在本场影片中在一次同级战斗中获胜，那么绷带的束缚会变得更紧，你的动作被其影响的程度也会加深，这会使你在使用这把剑时的攻击检定获得1DP的增强加值，</p><p>你也可以将绷带捆束到任意你已有的武器上，若如此做，则该武器继承绷带的所有特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
